/**
 * push-to-sanity.js
 *
 * Pushes a fully-drafted intake record to Sanity. For each run:
 *   1. Uploads specimen images from the local specimens/ folder
 *   2. Creates or replaces the Foundry document
 *   3. Creates or replaces the Typeface document with all schema fields
 *
 * Reads credentials from .env.local automatically — no env vars to export.
 * Edit scripts/intake-data.js for each new intake — do not edit this file.
 *
 * Requires the SANITY_API_TOKEN to have Editor (or higher) permissions.
 * A Viewer token will fail with 403 on write operations.
 *
 * Usage:
 *   node scripts/push-to-sanity.js
 */

const { createClient } = require('@sanity/client');
const fs   = require('fs');
const path = require('path');
const { readEnvLocal } = require('./env');
const { FOUNDRY, FOUNDRY_ID, SHARED, TYPEFACES } = require('./intake-data');

const env = readEnvLocal();

const client = createClient({
  projectId: env.NEXT_PUBLIC_SANITY_PROJECT_ID,
  dataset:   env.NEXT_PUBLIC_SANITY_DATASET || 'production',
  apiVersion: '2024-01-01',
  token:     env.SANITY_API_TOKEN,
  useCdn:    false,
});

// ── Helpers ───────────────────────────────────────────────────────────────────

async function uploadSpecimen(filename) {
  const filePath = path.join(process.cwd(), 'specimens', filename);
  if (!fs.existsSync(filePath)) {
    throw new Error(`Specimen file not found: specimens/${filename}`);
  }
  console.log(`  → Uploading ${filename}…`);
  const asset = await client.assets.upload('image', fs.createReadStream(filePath), {
    filename,
    contentType: 'image/jpeg',
  });
  console.log(`    ✓ Asset ID: ${asset._id}`);
  return asset;
}

function imageRef(asset) {
  return { _type: 'image', asset: { _type: 'reference', _ref: asset._id } };
}

// ── Main ──────────────────────────────────────────────────────────────────────

async function main() {
  console.log('\nTypeScout → Sanity push\n');

  // 1. Upload all specimens
  console.log('Uploading specimens…');
  const assets = {};
  for (const tf of TYPEFACES) {
    assets[tf._id] = await uploadSpecimen(tf.specimenFile);
    if (tf.specimenHeavyFile) {
      assets[`${tf._id}_heavy`] = await uploadSpecimen(tf.specimenHeavyFile);
    }
  }

  // 2. Foundry
  const foundryId = FOUNDRY_ID || await (async () => {
    console.log('\nCreating foundry…');
    const foundry = await client.createOrReplace(FOUNDRY);
    console.log(`  ✓ ${foundry._id} created`);
    return foundry._id;
  })();
  if (FOUNDRY_ID) {
    console.log(`\nFoundry already exists — using ${FOUNDRY_ID}`);
  }

  // 3. Typefaces
  console.log('\nCreating typefaces…');
  for (const tf of TYPEFACES) {
    await client.createOrReplace({
      _type:   'typeface',
      _id:     tf._id,
      name:    tf.name,
      slug:    { _type: 'slug', current: tf.slug },
      foundry: { _type: 'reference', _ref: foundryId },
      editorialNote:     tf.editorialNote,
      specimenImage:     imageRef(assets[tf._id]),
      ...(tf.specimenHeavyFile ? { specimenImageHeavy: imageRef(assets[`${tf._id}_heavy`]) } : {}),
      classification:    tf.classification,
      subClassification: tf.subClassification,
      personalityTags:   tf.personalityTags,
      useCaseTags:       tf.useCaseTags,
      width:             tf.width,
      xHeight:           tf.xHeight,
      contrast:          tf.contrast,
      typefaceURL:       tf.typefaceURL,
      rawKeywords:       tf.rawKeywords,
      hasItalics:        tf.hasItalics ?? false,
      ...SHARED,
    });
    console.log(`  ✓ ${tf._id} created`);
  }

  console.log('\n✓ All done. Records are live in Sanity.\n');
  console.log('Next: open your Sanity Studio to verify, then reload TypeScout at localhost:3000\n');
}

main().catch((err) => {
  console.error('\n✗ Push failed:', err.message);
  if (err.message.includes('403') || err.message.includes('Insufficient')) {
    console.error(
      '\n  Your SANITY_API_TOKEN needs Editor permissions (not Viewer).\n' +
      '  Go to sanity.io/manage → your project → API → Tokens → create a new Editor token,\n' +
      '  then update SANITY_API_TOKEN in .env.local and retry.\n'
    );
  }
  process.exit(1);
});
